// Import the necessary modules
const express = require('express');
const bodyParser = require('body-parser');
const mysql = require('mysql');

// Create an Express app
const app = express();

// Middleware to parse JSON bodies
app.use(bodyParser.json());

// Database connection
const db = mysql.createConnection({
  host: 'localhost',
  user: 'root',
  password: 'password',
  database: 'my_database'
});

// Connect to the database
db.connect((err) => {
  if (err) throw err;
  console.log('Connected to the database');
});

// Route to handle registration
app.post('/register', (req, res) => {
  const { name, email, password } = req.body;

  // Insert the new user into the database
  const query = 'INSERT INTO users (name, email, password) VALUES (?, ?, ?)';
  db.query(query, [name, email, password], (err, result) => {
    if (err) throw err;
    console.log('User registered successfully');
    res.status(201).send('User registered successfully');
  });
});

// Start the server
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});
```

This script sets up a simple Express server with a route to handle user registration. It uses the `mysql` module to connect to a MySQL database and insert new user records. Make sure to replace `'localhost'`, `'root'`, `'password'`, and `'my_database'` with your actual database connection details.
